package com.example.mod;

import net.minecraftforge.common.MinecraftForge;
import net.minecraftforge.event.TickEvent;
import net.minecraftforge.eventbus.api.SubscribeEvent;
import net.minecraftforge.fml.Mod;
import net.minecraftforge.fml.common.Mod.EventBusSubscriber.Bus;

@Mod("harmonix")
@EventBusSubscriber(modid = "harmonix", bus = Bus.FORGE)
public class HarmonixMod {

    public static DiscordantMeter discordantMeter = new DiscordantMeter();

    public HarmonixMod() {
        MinecraftForge.EVENT_BUS.register(this);
    }

    @SubscribeEvent
    public static void onPlayerTick(TickEvent.PlayerTickEvent event) {
        if (event.player.isUsingItem()) {
            Instrument instrument = getEquippedInstrument(event.player);
            if (instrument != null) {
                discordantMeter.adjust((int) (instrument.getSpeedMultiplier() + instrument.getDamageMultiplier()));
            }
        }
    }

    public static Instrument getEquippedInstrument(net.minecraft.world.entity.player.Player player) {
        // Logic to determine the equipped instrument
        return new Instrument("Harmonica", 0.5f, 0.3f);
    }
}

class DiscordantMeter {
    private int harmonyLevel;

    public void adjust(int change) {
        this.harmonyLevel += change;
        HarmonixMod.applyHarmonyEffect(HarmonixMod.minecraftClient.world, harmonyLevel);
        interactWithNPC(HarmonixMod.minecraftClient.player, npc); // Assuming a method to get the NPC
    }

    public int getHarmonyLevel() {
        return harmonyLevel;
    }
}

class Instrument {
    private String name;
    private float speedMultiplier;
    private float damageMultiplier;

    public Instrument(String name, float speedMultiplier, float damageMultiplier) {
        this.name = name;
        this.speedMultiplier = speedMultiplier;
        this.damageMultiplier = damageMultiplier;
    }

    public float getSpeedMultiplier() {
        return speedMultiplier;
    }

    public float getDamageMultiplier() {
        return damageMultiplier;
    }
}

class NPCInteractions {
    public static void interactWithNPC(net.minecraft.world.entity.player.Player player, net.minecraft.world.entity.npc.EntityNPC npc) {
        int harmonyLevel = HarmonixMod.discordantMeter.getHarmonyLevel();
        if (harmonyLevel > 0) {
            npc.setAggressive(false);
        } else {
            npc.setAggressive(true);
        }
    }
}
```

