package com.example.mod;

import net.minecraft.block.Block;
import net.minecraft.item.Item;
import net.minecraftforge.common.MinecraftForge;
import net.minecraftforge.event.RegistryEvent;
import net.minecraftforge.eventbus.api.SubscribeEvent;
import net.minecraftforge.fml.common.Mod;
import net.minecraftforge.registries.DeferredRegister;
import net.minecraftforge.registries.ForgeRegistries;

@Mod(SavoriaHarvestHome.MOD_ID)
public class SavoriaHarvestHome {
    public static final String MOD_ID = "savoria_harvest_home";

    private static final DeferredRegister<Item> ITEMS = DeferredRegister.create(ForgeRegistries.ITEMS, MOD_ID);
    private static final DeferredRegister<Block> BLOCKS = DeferredRegister.create(ForgeRegistries.BLOCKS, MOD_ID);

    public SavoriaHarvestHome() {
        ITEMS.register(bus -> MinecraftForge.EVENT_BUS.register(this));
        BLOCKS.register(bus -> MinecraftForge.EVENT_BUS.register(this));

        MinecraftForge.EVENT_BUS.register(this);
    }

    @SubscribeEvent
    public void onRegisterItems(RegistryEvent.Register<Item> event) {
        ITEMS.getEntries().forEach(entry -> entry.getValue().setRegistryName(MOD_ID, entry.getKey()));
        event.getRegistry().registerAll(
                ModItems.RARE_INGREDIENT
        );
    }

    @SubscribeEvent
    public void onRegisterBlocks(RegistryEvent.Register<Block> event) {
        BLOCKS.getEntries().forEach(entry -> entry.getValue().setRegistryName(MOD_ID, entry.getKey()));
        event.getRegistry().registerAll(
                ModBlocks.COOKING_TABLE
        );
    }
}
```

