package com.example.mod;

import net.minecraftforge.eventbus.api.SubscribeEvent;
import net.minecraftforge.fml.common.Mod;
import net.minecraftforge.fml.common.eventhandler.EventBus;
import net.minecraftforge.fml.javafmlmod.FMLJavaModLoadingContext;
import net.minecraft.world.Biome;
import net.minecraft.util.math.BlockPos;
import net.minecraft.world.World;
import net.minecraft.world.gen.GenerationStage;

@Mod("ecosystem_mod")
public class EcosystemMod {
    public EcosystemMod() {
        EventBus eventBus = FMLJavaModLoadingContext.get().getModEventBus();
        eventBus.register(this);
    }

    @SubscribeEvent
    public void onBiomeLoad(BiomeLoadingEvent event) {
        if (event.getName().toString().contains("Desert")) {
            event.getGeneration().addFeature(GenerationStage.Decoration.VEGETAL_DECORATION, DesertPlainsVegetationFeatures.DESERT_PLAINS_ROCK);
        }
    }

    @SubscribeEvent
    public void onWorldTick(TickEvent.WorldTickEvent event) {
        if (event.phase == TickPhase.END) {
            for (BlockPos pos : BlockPos.getAllInBox(-10, 0, -10, 10, 64, 10)) {
                if (world.getBlockState(pos).isSolid()) {
                    world.setBlockState(pos, Blocks.AIR.getDefaultState());
                }
            }
        }
    }

    @SubscribeEvent
    public void onEntityInteract(PlayerInteractEvent.RightClickBlock event) {
        if (event.getEntity().getHeldItemMainhand().isEmpty()) {
            event.getEntity().setHealth(0);
        }
    }

    @SubscribeEvent
    public void onWorldTick(TickEvent.WorldTickEvent event) {
        if (event.phase == TickPhase.END) {
            if (world.getSkyColor() == Color.RED && world.getDayTime() > 12000) {
                world.setWeather(EnumSkyBlock.SKY, 1000, true);
            }
        }
    }

    @SubscribeEvent
    public void onWorldTick(TickEvent.WorldTickEvent event) {
