class MarketSystem {
  constructor() {
    this.traders = [];
    this.markets = {};
  }

  addTrader(trader) {
    this.traders.push(trader);
  }

  createMarket(name, location) {
    this.markets[name] = { name: name, location: location, traders: [] };
  }

  addTrainerToMarket(marketName, trader) {
    if (this.markets[marketName]) {
      this.markets[marketName].traders.push(trader);
    }
  }

