    // Package declaration
    package com.example.mod;

    // Main class declaration
    @Mod.EventBusSubscriber(bus = Mod.EventBusSubscriber.Bus.FORGE)
    public static class EventHandler {

        @SubscribeEvent
        public static void onPlayerHit(PlayerEntity player, DamageSource damageSource) {
            int currentLifeForce = getPlayerLifeForce(player);
            if (currentLifeForce >= 100) {
                activateRampantMode(player);
            } else {
                increaseLifeForce(player, calculateDamageIncrease(damageSource));
            }
        }

        private static int getPlayerLifeForce(PlayerEntity player) {
            // Implement logic to get the current life force of the player
            return player.getHealth();
        }

