package com.example.mod;

import net.minecraft.entity.EntityType;
import net.minecraft.item.Item;
import net.minecraftforge.event.RegistryEvent;
import net.minecraftforge.fml.javafmlmod.FMLJavaModLoadingContext;
import net.minecraftforge.registries.DeferredRegister;
import net.minecraftforge.registries.IForgeRegistry;
import net.minecraftforge.registries.ObjectHolder;

public class MythicMenagerieMod {
    public static final String MOD_ID = "mythicmenagerie";

    // Deferred Register for entities
    private static final DeferredRegister<EntityType<?>> ENTITY_TYPES = DeferredRegister.create(EntityType.class, MOD_ID);

    // Deferred Register for items
    private static final DeferredRegister<Item> ITEMS = DeferredRegister.create(Item.class, MOD_ID);

    @ObjectHolder(MOD_ID)
    public static class RegistryHandler {
        public static final EntityType<MythicDragon> MYTHIC_DRAGON = ENTITY_TYPES.getObject("mythic_dragon");
        public static final Item MYTHIC_SWORD = ITEMS.getObject("mythic_sword");
    }

    public MythicMenagerieMod() {
        FMLJavaModLoadingContext.get().getModEventBus().addListener(this::setup);
    }

    private void setup(final RegistryEvent.Register<EntityType<?>> event) {
        ENTITY_TYPES.register(event);

        // Register items
        ITEMS.register(event);
    }
}
```

