  const engine = event.engine;
  if (engine instanceof Catapult) {
    console.log("Catapult activated!");
  } else if (engine instanceof Trebuchet) {
    console.log("Trebuchet activated!");
  } else if (engine instanceof Ballista) {
    console.log("Ballista activated!");
  }
}

// Define collision detection
function onEngineCollision(event) {
  const engine1 = event.engine1;
  const engine2 = event.engine2;
  if (engine1 instanceof Catapult && engine2 instanceof Trebuchet) {
    console.log("Catapult collided with Trebuchet!");
  } else if (engine1 instanceof Trebuchet && engine2 instanceof Ballista) {
    console.log("Trebuchet collided with Ballista!");
  }
}

// Register event listeners
addEvent("engine.activate", onEngineActivate);
addEvent("engine.collision", onEngineCollision);

// Define server-side logic for synchronization
function syncEngineState(engine, client) {
  const engineData = { power: engine.power, range: engine.range, speed: engine.speed };
  client.send(engineData);
}

// Implement dynamic crafting
function craftEngine(player, recipeId) {
  const recipe = craftingRecipes.find(r => r.id === recipeId);
  if (recipe) {
    for (const item of recipe.ingredients) {
      if (!player.inventory.has(item.item, item.count)) {
        console.log("Not enough resources to craft engine!");
        return;
      }
      player.inventory.remove(item.item, item.count);
    }
    const newEngine = createEngine(recipe.id);
    player.inventory.addItem(newEngine);
    console.log(`Crafted ${recipe.result}!`);
  } else {
    console.log("Invalid recipe!");
  }
}

// Helper function to create an engine instance
function createEngine(type) {
  switch (type) {
    case "catapult":
      return new Catapult();
    case "trebuchet":
      return new Trebuchet();
    case "ballista":
      return new Ballista();
    default:
      console.log("Invalid engine type!");
      return null;
  }
}

// Add a command to craft an engine
addCommand("craft_engine", (args) => {
  if (!args.length) {
    console.log("Usage: /craft_engine <catapult|trebuchet|ballista>");
    return;
  }
  const recipeId = args[0];
  craftEngine(player, recipeId);
});
