@Mod("riff_riot")
public class RiffRiotMod {

    public static final Item WIND_INSTRUMENT = new WindInstrument();
    public static final Item STRINGED_INSTRUMENT = new StringedInstrument();

    @ObjectHolder("riff_riot:wind_instrument")
    public static Item windInstrument;

    @ObjectHolder("riff_riot:stringed_instrument")
