class CustomBiomeBuilder extends Biome.Builder {

    public CustomBiomeBuilder() {
        super();
        this.addGenerationStage(Biome.GenerationStage.Decoration.UNDERGROUND_ORES);
        this.addFeature(GenerationStep.Decoration.VEGETAL_DECORATION, VegetationPlacements.OAK_TREE_CONFIG);
    }
}
